CODE_EXAMPLE:
// Before
void setValue(String name, int value) {
  if (name.equals("height")) {
    height = value;
  } else if (name.equals("width")) {
    width = value;
  }
}

// After
void setHeight(int value) { height = value; }
void setWidth(int value) { width = value; }

// Calls
setHeight(180);
setWidth(100);

UNIT_TEST_EXAMPLE:
@Test
public void testExplicitMethods() {
  Rectangle rect = new Rectangle();
  rect.setHeight(180);
  rect.setWidth(100);
  assertEquals(180, rect.getHeight());
}
